var e=[{id:`L2_1`,type:`dialog`,speaker:`PLAYER_SPORTS_NPC_BLUE`,text:{KOREA:`좋아! 빼앗았다!`,JPN:`よし！　取れた！`,ENG:`Yeah, I got it!`,TWN:`太好了！拿到了！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`PLAYER_SPORTS_NPC_RED`,text:{KOREA:`아깝다! 손을 조금만 더 뻗으면 됐는데......!`,JPN:`惜しい！　もう少し手を伸ばせたら届いたのに……！`,ENG:`Bummer! I was so close!`,TWN:`真可惜！就差一點兒就拿到了……！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`크윽! 임시 편입생! 경기 내내 노골적으로 나만 노리잖아!`,JPN:`くっ！　臨時編入生！　露骨に私ばっか狙ってるじゃない！？`,ENG:`Bah! You, temporary transfer student! You're being badly after me throughout the whole game!`,TWN:`咳咳！臨時插班生！你怎麼一直盯著我不放！`},stage:{bg:`SPORTSGROUND`,slots:{L:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_HATE`},C:null,R:{char_id:`SEOYOON_ALT_SPORTS_NOBG`,face:`UNIT_SERIOUS`}}}},{id:`L13_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`경기를 너무 치사하게 하는 거 아냐?!`,JPN:`試合なのにずるいわよ！！`,ENG:`Why are you being so nasty?`,TWN:`你不覺得自己太卑鄙了嗎？`},stage:{bg:`SPORTSGROUND`,slots:{L:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_IDLE`},C:null,R:{char_id:`SEOYOON_ALT_SPORTS_NOBG`,face:`UNIT_SERIOUS`}}}},{id:`L14_1`,type:`dialog`,speaker:`SEOYOON_ALT_SPORTS_NOBG`,text:{KOREA:`치사하다고 느꼈다면 계획대로네.`,JPN:`ずるいと思ったなら計画どおりよ。`,ENG:`If you think I'm being nasty, everything is going as I planned.`,TWN:`你覺得我卑鄙？那就對了。`},stage:{bg:`SPORTSGROUND`,slots:{L:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_IDLE`},C:null,R:{char_id:`SEOYOON_ALT_SPORTS_NOBG`,face:`UNIT_SERIOUS`}}}},{id:`L15_1`,type:`dialog`,speaker:`SEOYOON_ALT_SPORTS_NOBG`,text:{KOREA:`원래 적팀의 에이스를 마크하는 게 전략의 기본이니까.`,JPN:`敵チームのエースをマークするのが戦略の基本だから。`,ENG:`Strategy 101: keep the enemy's ace in check.`,TWN:`牽制敵隊的王牌本就是最基本的策略。`},stage:{bg:`SPORTSGROUND`,slots:{L:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_IDLE`},C:null,R:{char_id:`SEOYOON_ALT_SPORTS_NOBG`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`우리 팀 머저리들은 다 뭘 하고 있는 거야!`,JPN:`うちのチームの無能どもは何してるの！？`,ENG:`What are the other idiots on our team doing?`,TWN:`我們隊的蠢貨都在幹什麼！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_HATE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`이래선 내가 활약할 수가 없잖아!`,JPN:`これじゃあ私が活躍できないじゃない！`,ENG:`I can't shine in a situation like this!`,TWN:`這樣我根本就沒辦法大展身手！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`PENCIL_SCHOOL_NPC_NULL`,text:{KOREA:`방금 전까지 혼자서 전부 상대할 것처럼 떵떵거리더니 뭐 하는 거야!`,JPN:`さっきまで一人で全員相手にできるって威張ってたのに何してるの！`,ENG:`Hey, you were bragging that you could take care of them all by yourself! What are you doing now?`,TWN:`剛剛還一副以一擋百的架勢呢，現在怎麼了！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`PENCIL_SCHOOL_NPC_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`PENCIL_SCHOOL_NPC_NULL`,text:{KOREA:`팀전이니까 한 명만 쫓지 말고 다른 팀원들도 도와 줘야지!`,JPN:`チーム戦なんだから一人ばかり追いかけてないで、他のチームメンバーも助けてあげて！`,ENG:`This is a team match! Stop following her and help the others!`,TWN:`這是團隊戰，不要只追著一個人跑，也要幫幫其他隊員才是！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`PENCIL_SCHOOL_NPC_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`칫...... 낙오자 주제에 목소리만 커선......!`,JPN:`チッ……落ちこぼれのくせに声だけはデカいじゃない……！`,ENG:`Hmpf, don't tell me what to do, loser!`,TWN:`切……區區一個失敗者，口氣倒是不小……！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_HATE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`누가 좋아서 이 녀석만 상대하고 있는 줄 알아?!`,JPN:`私だって好きでこいつだけを相手してるわけじゃないわよ！？`,ENG:`Do you think I'm only dealing with her because I want to?`,TWN:`你以為我願意這樣？！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_SERIOUS`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`TWINTAIL_ACADEMY_SPORTS_NOBG`,text:{KOREA:`그러는 넌 네 꼬리는 어디다 두고 다니는 건데!`,JPN:`そういうあんたのしっぽはどこなの！`,ENG:`Where did you leave your tail, anyway?`,TWN:`還有，你的尾巴丟哪兒去了！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`TWINTAIL_ACADEMY_SPORTS_NOBG`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`PENCIL_SCHOOL_NPC_NULL`,text:{KOREA:`응? 내 꼬리?`,JPN:`ん？　私のしっぽ？`,ENG:`Huh? My tail?`,TWN:`嗯？我的尾巴？`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`PENCIL_SCHOOL_NPC_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`PENCIL_SCHOOL_NPC_NULL`,text:{KOREA:`어, 어라? 이게 언제 사라졌지?!`,JPN:`あ、あれ？　いつの間に消えたの！？`,ENG:`Err, when did I lose it?`,TWN:`哎，哎呀？尾巴什麼時候不見的？！`},stage:{bg:`SPORTSGROUND`,slots:{L:null,C:{char_id:`PENCIL_SCHOOL_NPC_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};